module top_module(
  input clk,
  input rst,
  input [7:0] obf_a,
  input [7:0] b,
  input [1:0] ctrl,
  output reg [7:0] result
);always @(posedge clk) begin
    if (rst) begin
      result <= 0;
    end else begin
      case (ctrl)
        2'b00: result <= obf_a + b;
        2'b01: result <= obf_a - b;
        2'b10: result <= obf_a * b;
        2'b11: result <= obf_a / b;
        default: result <= 0;
      endcase
    end
  end

endmodule
